      if (sess.pid == null) continue;
      if (!probeProcess(sess.pid)) {
        stale.push({
          sessionId: sess.id,
          itemId: sess.item_id,
          phase: sess.phase,
          pid: sess.pid,
          pgid: sess.pgid,
